                }
                if (prop.NameEquals("publicNetworkAccess"u8))
                {
                    if (prop.Value.ValueKind == JsonValueKind.Null)
                    {
                        continue;
                    }
                    publicNetworkAccess = new PublicNetworkAccess(prop.Value.GetString());
                    continue;
                }
                if (prop.NameEquals("serverlessComputeSettings"u8))
                {
                    if (prop.Value.ValueKind == JsonValueKind.Null)
                    {
                        continue;
                    }
                    serverlessComputeSettings = ServerlessComputeSettings.DeserializeServerlessComputeSettings(prop.Value, options);
                    continue;
                }
                if (prop.NameEquals("serviceManagedResourcesSettings"u8))
                {
                    if (prop.Value.ValueKind == JsonValueKind.Null)
                    {
                        continue;
                    }
                    serviceManagedResourcesSettings = ServiceManagedResourcesSettings.DeserializeServiceManagedResourcesSettings(prop.Value, options);
                    continue;
                }
                if (prop.NameEquals("serviceProvisionedResourceGroup"u8))
                {
                    serviceProvisionedResourceGroup = prop.Value.GetString();
                    continue;
                }
                if (prop.NameEquals("sharedPrivateLinkResources"u8))
                {
                    if (prop.Value.ValueKind == JsonValueKind.Null)
                    {
                        continue;
                    }
                    List<MachineLearningSharedPrivateLinkResource> array = new List<MachineLearningSharedPrivateLinkResource>();
                    foreach (var item in prop.Value.EnumerateArray())
                    {
                        array.Add(MachineLearningSharedPrivateLinkResource.DeserializeMachineLearningSharedPrivateLinkResource(item, options));
                    }
                    sharedPrivateLinkResources = array;
                    continue;
                }
                if (prop.NameEquals("softDeleteRetentionInDays"u8))
                {
                    if (prop.Value.ValueKind == JsonValueKind.Null)
                    {
                        continue;
                    }
                    softDeleteRetentionInDays = prop.Value.GetInt32();
                    continue;
                }
                if (prop.NameEquals("storageAccount"u8))
                {
                    storageAccount = prop.Value.GetString();
                    continue;
                }
                if (prop.NameEquals("storageAccounts"u8))
                {
                    if (prop.Value.ValueKind == JsonValueKind.Null)
                    {
                        continue;
                    }
                    List<string> array = new List<string>();
                    foreach (var item in prop.Value.EnumerateArray())
                    {
                        if (item.ValueKind == JsonValueKind.Null)
                        {
                            array.Add(null);
                        }
                        else
                        {
                            array.Add(item.GetString());
                        }
                    }
                    storageAccounts = array;
                    continue;
                }
                if (prop.NameEquals("storageHnsEnabled"u8))
                {
                    if (prop.Value.ValueKind == JsonValueKind.Null)
                    {
                        continue;
                    }
                    isStorageHnsEnabled = prop.Value.GetBoolean();
                    continue;
                }
                if (prop.NameEquals("systemDatastoresAuthMode"u8))
                {
                    if (prop.Value.ValueKind == JsonValueKind.Null)
                    {
                        continue;
                    }
                    systemDatastoresAuthMode = new SystemDatastoresAuthMode(prop.Value.GetString());
                    continue;
                }
                if (prop.NameEquals("tenantId"u8))
                {
                    if (prop.Value.ValueKind == JsonValueKind.Null)
                    {
                        continue;
                    }
                    tenantId = new Guid(prop.Value.GetString());
                    continue;
                }
                if (prop.NameEquals("v1LegacyMode"u8))
                {
                    if (prop.Value.ValueKind == JsonValueKind.Null)
                    {
                        continue;
                    }
                    isV1LegacyMode = prop.Value.GetBoolean();
                    continue;
                }
                if (prop.NameEquals("workspaceHubConfig"u8))
                {
                    if (prop.Value.ValueKind == JsonValueKind.Null)
                    {
                        continue;
                    }
                    workspaceHubConfig = WorkspaceHubConfig.DeserializeWorkspaceHubConfig(prop.Value, options);
                    continue;
                }
                if (prop.NameEquals("workspaceId"u8))
                {
                    workspaceId = prop.Value.GetString();
                    continue;
                }
                if (options.Format != "W")
                {
                    additionalBinaryDataProperties.Add(prop.Name, BinaryData.FromString(prop.Value.GetRawText()));
                }
            }
            return new WorkspaceProperties(
                agentsEndpointUri,
                allowPublicAccessWhenBehindVnet,
                allowRoleAssignmentOnRG,
                applicationInsights,
                associatedWorkspaces ?? new ChangeTrackingList<string>(),
                containerRegistries ?? new ChangeTrackingList<string>(),
                containerRegistry,
                description,
                discoveryUri,
                enableDataIsolation,
                enableServiceSideCMKEncryption,
                enableSimplifiedCmk,
                enableSoftwareBillOfMaterials,
                encryption,
                existingWorkspaces ?? new ChangeTrackingList<string>(),
                featureStoreSettings,
                friendlyName,
                isHbiWorkspace,
                hubResourceId,
                imageBuildCompute,
                ipAllowlist ?? new ChangeTrackingList<string>(),
                keyVault,
                keyVaults ?? new ChangeTrackingList<string>(),
                managedNetwork,
                mlFlowTrackingUri,
                networkAcls,
                notebookInfo,
                primaryUserAssignedIdentity,
                privateEndpointConnections ?? new ChangeTrackingList<MachineLearningPrivateEndpointConnectionData>(),
                privateLinkCount,
                provisionNetworkNow,
                provisioningState,
                publicNetworkAccess,
                serverlessComputeSettings,
                serviceManagedResourcesSettings,
                serviceProvisionedResourceGroup,
                sharedPrivateLinkResources ?? new ChangeTrackingList<MachineLearningSharedPrivateLinkResource>(),
                softDeleteRetentionInDays,
                storageAccount,
                storageAccounts ?? new ChangeTrackingList<string>(),
                isStorageHnsEnabled,
                systemDatastoresAuthMode,
                tenantId,
                isV1LegacyMode,
                workspaceHubConfig,
                workspaceId,
                additionalBinaryDataProperties);
        }
    }
